window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2015>1","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"From the above diagram, which major condition may have encouraged candidtates to engage in examination malpractice?","images":["data:image/png;base64,"],"options":{"A":"Public perception that it is normal to cheat","B":"Inadequate preparation for the examination","C":"The supervisors are negligent","D":"School authorities encourage cheating"},"answer":"B","explanation":"Inadequate preparation for the examination is a major condition that may have encouraged candidates to engage in examination malpractice.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>2","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Which of the following statements may be true about the behaviour of the candidates in the diagram?","images":["data:image/png;base64,"],"options":{"A":"The candidates are doing what is ethical","B":"Candidates involved in malpractice should be banned for life","C":"Their action can also affect innocent candidates","D":"Their misconduct will guarantee a reliable certificate"},"answer":"C","explanation":"Their action can also affect innocent candidates. This is because innocent students may be caught between.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>3","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Based on the above diagram, the candidates would not have cheated if","images":["data:image/png;base64,"],"options":{"A":"They were well-spaced","B":"There was an invigilator","C":"They were hard working","D":"There was no body to copy from"},"answer":"C","explanation":"The candidate would not have cheated if they were hardworking.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>4","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)","question":"In which year did the United Nations General Assembly adopt the Universal Declaration of Human Rights?","images":[],"options":{"A":"1945","B":"1946","C":"1947","D":"1948"},"answer":"D","explanation":"The Universal Declaration of Human Rights was adopted by the United Nations General Assembly on December 10, 1948. This declaration is a milestone document in the history of human rights that sets out, for the first time, fundamental human rights to be universally protected.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>5","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Use the picture below to answer this question      The road signs in the picture above indicate","images":["data:image/png;base64,"],"options":{"A":"Two ways traffic ahead","B":"Dualised carrage way ahead","C":"Two junctions ahead","D":"Two exit routa ahead"},"answer":"A","explanation":"It indicates a two way traffic ahead. This is the most appropriate answer.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>6","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Two forms of road signs are regulatory and","images":[],"options":{"A":"punitive","B":"informative","C":"persuasive","D":"inhibitive"},"answer":"B","explanation":"Road signs are typically divided into several categories. Regulatory signs are one of them, which are designed to instruct road users on what they must or should do (or not do) under a given set of circumstances. The other type mentioned in the question is informative signs. These signs give information about destinations, distances, alternative routes, points of interest, or other geographical, historical, or cultural information.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>7","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"Which of the following factors does not affect interpersonal relationship?","images":[],"options":{"A":"Communication","B":"Withdrawal","C":"Compatibility","D":"Forgiveness"},"answer":"C","explanation":"Interpersonal relationships are social associations, connections, or affiliations between two or more people. They vary in differing levels of intimacy and sharing, implying the discovery or establishment of common ground, and may be centered around something shared in common. The factors that affect interpersonal relationships include communication, withdrawal, and forgiveness. However, compatibility does not affect interpersonal relationships as it is a state, not a factor. It is the ability of two or more things to exist or work together without conflict.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>8","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM","question":"The following cadre of students are the main target for campus cult membership except","images":[],"options":{"A":"students from wealth homes","B":"students from influential parents","C":"bold and morally sound students","D":"wayward and fun-loving students"},"answer":"C","explanation":"Campus cults often target students who are easily influenced or who seek a sense of belonging, which can often be found in students from wealthy homes, students from influential parents, and wayward and fun-loving students. However, bold and morally sound students are less likely to be targeted for campus cult membership because they are more likely to resist the pressure and manipulation tactics used by cults. They have a strong moral compass and are not easily swayed by peer pressure or the promise of power or popularity.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>9","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"The National Agency for Food and Drug Administration and Control (NAFDAC) was established in","images":[],"options":{"A":"1993","B":"1996","C":"1999","D":"2001"},"answer":"A","explanation":"The National Agency for Food and Drug Administration and Control (NAFDAC) was established in 1993. NAFDAC is a Nigerian federal agency under the Federal Ministry of Health that is responsible for regulating and controlling the manufacture, importation, exportation, advertisement, distribution, sale and use of food, drugs, cosmetics, medical devices, chemicals and packaged water. Its goal is to ensure the health and safety of the Nigerian public.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>10","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING","question":"National Agency for the Prohibition of Traffic in Persons (NAPTIP) is an initiative of","images":[],"options":{"A":"Federal Government of Nigeria","B":"United States Agency for International Development","C":"Women Trafficking and Child Labour Eradication Foundation","D":"United States Office on Drugs and Crime"},"answer":"A","explanation":"The National Agency for the Prohibition of Traffic in Persons (NAPTIP) is an initiative of the Federal Government of Nigeria. It was established in 2003 in response to the high rate of human trafficking in the country. The agency is tasked with enforcing the law that prohibits trafficking in persons, coordinating and supervising all functions of other agencies and bodies in relation to traffic in persons, and adopting measures aimed at the elimination of traffic in persons.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>11","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS","question":"World AIDS day is observed on","images":[],"options":{"A":"20th May","B":"30th July","C":"27th August","D":"1st December"},"answer":"D","explanation":"World AIDS Day is observed on 1st December every year. It is dedicated to raising awareness of the AIDS pandemic caused by the spread of HIV infection and mourning those who have died of the disease.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>12","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"An enabling environment created to help an individual have effective control of his/her situation is known as","images":[],"options":{"A":"reinforcement","B":"empowerment","C":"endownment","D":"enhancement"},"answer":"B","explanation":"Empowerment refers to the process of becoming stronger and more confident, especially in controlling one's life and claiming one's rights. An enabling environment created to help an individual have effective control of his/her situation is known as empowerment.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>13","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"In order to avoid undue interference in the process of governance, there should be","images":[],"options":{"A":"clear cut separation of governmental powers.","B":"proper fusion of governmental powers and functions.","C":"more roles for traditional rulers in the governmental process.","D":"additional responsibility for local government council."},"answer":"A","explanation":"The principle of separation of powers is a doctrine of constitutional law under which the three branches of government (executive, legislative, and judicial) are kept separate. This is to prevent abuse of power and to safeguard freedom for all. This principle is clearly stated in many democratic constitutions including the United States Constitution and the Constitution of the Federal Republic of Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>14","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"Red-tapism is one of the shortcomings of","images":[],"options":{"A":"private enterprise","B":"public service","C":"non-governmental organization","D":"pressure groups"},"answer":"B","explanation":"Red-tapism refers to excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. It is usually applied to governments, corporations, and other large organizations. Therefore, it is a shortcoming of the public service, not private enterprises, non-governmental organizations, or pressure groups.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>15","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM","question":"An ideology that aims at promoting national consciousness and identity is","images":[],"options":{"A":"nationalism","B":"socialization","C":"civic culture","D":"progressivism"},"answer":"A","explanation":"Nationalism is an ideology that promotes national consciousness and identity. It emphasizes the interests of a particular nation (as in a group of people) especially with the aim of gaining and maintaining the nation's sovereignty (self-governance) over its homeland. Nationalism holds that each nation should govern itself, free from outside interference (self-determination), that a nation is a natural and ideal basis for a polity, and that the nation is the only rightful source of political power (popular sovereignty).","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>16","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CHARACTERISTICS OF HUMAN RIGHTS","question":"Human rights are described as inviolable mainly because they are","images":[],"options":{"A":"authoritative declaration","B":"enforcable everywhere","C":"not to be unnecessarily taken away","D":"legal declaration instruments"},"answer":"C","explanation":"Human rights are described as inviolable mainly because they are not to be unnecessarily taken away. Human rights are the basic rights and freedoms to which all individuals are entitled, regardless of nationality, sex, national or ethnic origin, race, religion, language, or other status. These rights include the right to life and liberty, freedom from slavery and torture, freedom of opinion and expression, the right to work and education, and many more. They are protected and upheld by international and national laws and treaties.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>17","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Law and order can best be maintained in Nigeria through the","images":[],"options":{"A":"prohibition of public protest","B":"enforcement of rules and regulations","C":"use of divide and rule policy","D":"promotion of indigenization policy"},"answer":"B","explanation":"Law and order can best be maintained in any society through the enforcement of rules and regulations. This is because rules and regulations provide a guideline for acceptable behavior and actions in a society. When these rules and regulations are enforced, it ensures that individuals adhere to them, thereby maintaining law and order. Prohibition of public protest, use of divide and rule policy, and promotion of indigenization policy are not direct methods of maintaining law and order.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>18","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"A responsible parent is one who","images":[],"options":{"A":"cares and provides for the children","B":"indulges the children because of love","C":"works in order to receive salary","D":"employs house-helps to take care of the children"},"answer":"A","explanation":"A responsible parent is one who cares and provides for the children. This involves providing for their basic needs such as food, shelter, clothing, education, and also emotional needs like love, care, and support. Indulging children because of love can lead to spoiling them and is not a sign of responsible parenting. Working in order to receive salary is a general responsibility of every working adult, not specifically a parent. Employing house-helps to take care of the children does not necessarily mean the parent is responsible, as the primary care and responsibility still lies with the parent.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>19","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"A major way of promoting responsible parenthood is through","images":[],"options":{"A":"sex education","B":"sound education","C":"population control measures","D":"tax reduction measures"},"answer":"A","explanation":"Responsible parenthood can be promoted through sex education. This is because sex education provides knowledge about sexual health, reproduction, and contraceptive methods. It also teaches about the responsibilities and consequences of sexual behavior, thereby promoting responsible parenthood.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>20","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : TYPES OF INTERPERSONAL RELATIONSHIPS","question":"Which of the following is not included in the stages of interpersonal relationships?","images":[],"options":{"A":"Rejuvenation","B":"Deterioration","C":"Termination","D":"Continuation"},"answer":"A","explanation":"The stages of interpersonal relationships typically include initiation, experimentation, intensifying, integration, bonding, and then either deterioration, termination, or continuation. Rejuvenation is not typically included as a stage in this process.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>21","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM","question":"Cultism in tertiary institution in Nigeria was originally introduced to","images":[],"options":{"A":"perpetuate the use of local gin and alcohol","B":"harass opponents of university administrators","C":"fight colonialism and oppressive rules","D":"promote inter-communal marriages"},"answer":"C","explanation":"Cultism in tertiary institutions in Nigeria was originally introduced to fight colonialism and oppressive rules. The first known cult group, the Pyrates Confraternity (also known as National Association of Sea Dogs), was formed in the University of Ibadan in 1952 by Nobel laureate Wole Soyinka and his friends. It was formed to advocate for the rights of the students and fight against the oppressive rules of the colonial masters.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>22","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"Which of the following is not a function of the National Drug Law Enforcement Agency (NDLEA)?","images":[],"options":{"A":"Applying and implementing all drug laws","B":"Arresting, investigating and prosecuting drug traffickers","C":"Undertaking the registration of companies dealing in drugs","D":"Carrying out enlightenment campaigns on drug trafficking"},"answer":"C","explanation":"The National Drug Law Enforcement Agency (NDLEA) is a Federal agency in Nigeria charged with eliminating the growing, processing, manufacturing, selling, exporting, and trafficking of hard drugs. The agency does not undertake the registration of companies dealing in drugs. This is typically the responsibility of the National Agency for Food and Drug Administration and Control (NAFDAC).","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>23","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"An individual who finds it difficult to control in-take of drug is known as drug","images":[],"options":{"A":"baron","B":"trafficker","C":"mogul","D":"addict"},"answer":"D","explanation":"An individual who finds it difficult to control in-take of drug is known as a drug addict. A drug addict is a person who is unable to stop using a drug, despite the negative effects it has on their life. This is different from a drug baron, trafficker, or mogul, who are involved in the production, distribution, or sale of drugs.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>24","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"The NDLEA personnel are not usually found in","images":[],"options":{"A":"international airports","B":"seaports","C":"border crossings","D":"foreign embassies"},"answer":"D","explanation":"The NDLEA (National Drug Law Enforcement Agency) personnel are not usually found in foreign embassies. The NDLEA is a Nigerian federal agency tasked with preventing the production, importation, possession, distribution and use of drugs. They are typically found in places where drug trafficking is likely to occur, such as international airports, seaports, and border crossings. However, they do not typically operate in foreign embassies, as these are considered the sovereign territory of the foreign country.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>25","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"Which of the following statements best describes Human Trafficking?","images":[],"options":{"A":"Recruitment of youths as casual workers","B":"Desperate desire by youths to travel abroad","C":"Buying and selling of humans for selfish purposes","D":"Transportation of goods and services through human portage"},"answer":"C","explanation":"Human trafficking is a crime that involves the exploitation of a person through force, fraud, or coercion. This exploitation often involves forced labor, sexual exploitation, or other forms of abuse. Therefore, the option 'Buying and selling of humans for selfish purposes' best describes human trafficking. The other options do not accurately describe the nature of human trafficking.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>26","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.    From the above write-up, what category of Kantoguan youths deserves to be effectively empowered?","images":[],"options":{"A":"Children of the ruling political class","B":"Unemployed youths and school drop-outs","C":"University undergraduates","D":"Youths wing of religious organisations"},"answer":"B","explanation":"From the write-up, it is clear that the category of Kantoguan youths that deserves to be effectively empowered are the 'Unemployed youths and school drop-outs'. These are the youths who are being engaged in crimes such as political thuggery, rigging, stuffing of ballot boxes and other related electoral offences because they have no means of livelihood. Empowering them through entrepreneurial skill acquisition programs and start-up funds for small scale businesses would reduce their chances of being engaged in such activities.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>27","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.  The responsibility of empowering the youths rests mostly with","images":[],"options":{"A":"the political class","B":"religious organisations","C":"university administrators","D":"national government"},"answer":"D","explanation":"From the passage, it is clear that the responsibility of empowering the youths rests mostly with the national government. The passage mentions that it is the duty of the government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This implies that the national government has the primary responsibility to empower the youths.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>28","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT","question":"Use the write-up below to answer this question   One major trend in Kantoga Republi today, especially during elections, is the engagement of youths by some politicians for political thuggery, rigging, stuffing of ballot boxes and other related electoral offences. Most of the youths who are engaged in these crimes have no means of livelihood or are school drop-outs. These youths are Kantoguans who ought to benefit from the enormous wealth and resources of the nation. Unfortunately, this is not the case at the moment. Indeed, it is the duty of government, especially at the centre, to provide entrepreneurial skill acquisition programme and start-up funds for small scale businesses to empower the youths. This will reduce the chances of engaging youth in wrong purposes.  Based on the write-up, what immediate measures can those in authority take to empower the youths?","images":[],"options":{"A":"Build more youth orientation camps in the country","B":"Enhance religious and moral education in schools and colleges","C":"Provide entrepreneurial training with adequate fund","D":"Provide free meal for the teeming unemployed youths"},"answer":"C","explanation":"The passage suggests that the immediate measures those in authority can take to empower the youths include providing entrepreneurial skill acquisition programme and start-up funds for small scale businesses. This aligns with option 3, which suggests providing entrepreneurial training with adequate fund. The other options do not directly address the issue of empowering the youths as suggested in the passage.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>29","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"A very important segment of the society which is distinct from government, business and home is the","images":[],"options":{"A":"civil society","B":"public service","C":"mass media","D":"traditional institution"},"answer":"A","explanation":"The civil society is a very important segment of the society which is distinct from government, business and home. Civil society includes non-governmental organizations and institutions that manifest interests and will of citizens. They include organizations such as community groups, non-profit organizations, and independent foundations.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>30","subject":"Civic Education","year":"2015","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS","question":"HIV/AIDS is generally described as terminal in nature because it is","images":[],"options":{"A":"preventable","B":"transmittable","C":"avertable","D":"incurable"},"answer":"D","explanation":"HIV/AIDS is generally described as terminal in nature because it is incurable. While there are treatments that can slow the course of the disease, there is currently no known cure for HIV/AIDS. This makes the disease terminal, as it eventually leads to death.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>31","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS","question":"Inter-communal relationship is best described as","images":[],"options":{"A":"the interaction between individuals, groups or organisation with common aspirations.","B":"the interaction among individuals and professionals in a society.","C":"loyalty to community leaders so as to achieve rapid communal development.","D":"respect for collective national symbols in order to foster nationalistic feeling."},"answer":"A","explanation":"Inter-communal relationship refers to the interaction between different communities. This interaction can be between individuals, groups, or organizations that share common aspirations. It involves mutual understanding, cooperation, and respect among different communities. Therefore, the first option is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>32","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : QUALITIES/CHARACTERISTICS OF CIVIL SOCIETY; I.E. ACCOUNTABILITY, FAIRNESS, JUSTICE, EQUITY ETC","question":"A situation whereby someone is obliged to inform a superior about his actions and decisions for the purpose of control is","images":[],"options":{"A":"probity","B":"self-discipline","C":"accountability","D":"fair play"},"answer":"C","explanation":"The situation described in the question is known as accountability. Accountability is a concept in ethics and governance with several meanings. It is often used synonymously with such concepts as responsibility, answerability, blameworthiness, liability, and other terms associated with the expectation of account-giving. In governance, accountability is the acknowledgment and assumption of responsibility for actions, decisions, and policies including the administration, governance, and implementation within the scope of the role or employment position and encompassing the obligation to report, explain and be answerable for resulting consequences.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>33","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"\"All human beings are born free and equal in dignity and rights. They are endowed with reason and conscience and should act towards one another in a spirit of brotherhood\".   The above quotation summarizes the","images":[],"options":{"A":"Universal Declaration of Human Rights.","B":"African charter on Human Rights.","C":"Geneva Conventions and protocols.","D":"United Nations Organization Charter."},"answer":"A","explanation":"The quote is from the Universal Declaration of Human Rights. The Universal Declaration of Human Rights (UDHR) is a historic document that was adopted by the United Nations General Assembly at its third session on 10 December 1948 as Resolution 217 at the Palais de Chaillot in Paris, France. It consists of 30 articles which have been elaborated in subsequent international treaties, regional human rights instruments, national constitutions, and other laws. The quote is the first article of the UDHR.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>34","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD","question":"Effective and responsible parenthood is primarily","images":[],"options":{"A":"a national duty","B":"a military duty","C":"a political duty","D":"an economic duty"},"answer":"A","explanation":"None of the options is correct. Effective and responsible parenthood is primarily a personal duty. It is the responsibility of parents to provide for the physical, emotional, and social well-being of their children. This includes providing food, shelter, clothing, education, and healthcare, as well as nurturing, guidance, and love. While the state and society have roles to play in supporting parents, the primary responsibility lies with the parents themselves.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>35","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTERPERSONAL RELATIONSHIPS","question":"Association and affiliation between two or more people is called","images":[],"options":{"A":"multilateral relations","B":"bilateral relations","C":"inter-communal relations","D":"inter-personal relations"},"answer":"D","explanation":"The term 'inter-personal relations' refers to the social association, connection, or affiliation between two or more people. It varies in differing levels of intimacy and sharing, involving the discovery or establishment of common ground, and may be centered around something shared in common. The other options do not accurately describe the association and affiliation between two or more people.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>36","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"A bill passed by the National Assembly requires the assent of the president before it becomes law. The law can be declared null and void by the court of law. The process above emphasizes the","images":[],"options":{"A":"supremacy of judiciary over other arms of government","B":"relationship among the arms of government","C":"importance of law makers in a democracy","D":"fundamentals of the rule of law"},"answer":"B","explanation":"The process described in the question emphasizes the relationship among the arms of government. In a democratic system, the three arms of government (the Executive, Legislature, and Judiciary) work together to make, implement, and interpret laws. The process of a bill becoming law involves the Legislature (National Assembly) passing the bill, the Executive (President) assenting to the bill, and the Judiciary (Court of Law) having the power to declare the law null and void if it contravenes the constitution. This shows the relationship and interdependence among the three arms of government.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>37","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"The idea that \"Law should be impartial with the people who break it\" implies","images":[],"options":{"A":"principle of fair hearing","B":"right to legal representation","C":"equality before the law","D":"prerogative writ of habeas corpus"},"answer":"C","explanation":"The statement 'Law should be impartial with the people who break it' implies that everyone is equal before the law. This is a fundamental principle in legal systems where each person is subject to the law and no one is above it. It ensures that everyone is treated equally irrespective of their social status, wealth, or power.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>38","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF NATIONAL DEVELOPMENT","question":"The foreign policy objectives of Nigeria as enshrined in the 1999 Constitution exclude the promotion of","images":[],"options":{"A":"national interest","B":"African integration","C":"support for donor agencies","D":"just world economic order"},"answer":"C","explanation":"The foreign policy objectives of Nigeria as enshrined in the 1999 Constitution include the promotion of national interest, African integration, and a just world economic order. However, support for donor agencies is not explicitly stated as a foreign policy objective in the constitution. Therefore, the promotion of support for donor agencies is excluded from the foreign policy objectives of Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>39","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"Democracy can promote national development if there is","images":[],"options":{"A":"good governance","B":"promotion of culture","C":"immunity for leaders","D":"registration of parties"},"answer":"A","explanation":"Democracy can promote national development if there is good governance. Good governance refers to the management of resources in a manner that is transparent, accountable, equitable and responsive to the needs of the people. It ensures that the government is effective and efficient in its operations, respects the rule of law, and promotes the participation of citizens in decision-making processes. This leads to national development as resources are used optimally, corruption is minimized, and the needs and interests of the people are prioritized.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>40","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"A major civil society group which campaigned against military rule prior to the advent of the Four Republic in Nigeria is the","images":[],"options":{"A":"Campaign for Democracy","B":"Save Nigeria Group","C":"Civil Liberties Organization","D":"National Democracy Coalition"},"answer":"A","explanation":"The Campaign for Democracy (CD) was a major civil society group that campaigned against military rule prior to the advent of the Fourth Republic in Nigeria. The group was instrumental in mobilizing public opinion and pressure against the military regime, advocating for a return to democratic governance. The other options listed, while they are recognized civil society groups in Nigeria, they did not play as significant a role as the CD in the campaign against military rule.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>41","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"Which of the following functions is not performed by the Public Service Commission?","images":[],"options":{"A":"Evaluating the performance of ministries and departments","B":"Advising government on technical matters","C":"Preparing the annual budget and assenting to it","D":"Organising enlightenment programme and training"},"answer":"C","explanation":"The Public Service Commission does not prepare the annual budget and assent to it. This function is performed by the executive arm of government, specifically the Ministry of Finance and the President or Governor. The Public Service Commission is responsible for the recruitment, promotion, and discipline of civil servants. It also advises the government on civil service matters, evaluates the performance of ministries and departments, and organizes training programs.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>42","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC","question":"Which of the following is a major challenge to civil society in Nigeria?","images":[],"options":{"A":"Value disorientation","B":"Diverse political interests","C":"Inadequate funding","D":"Unstable political system"},"answer":"C","explanation":"Inadequate funding is a major challenge to civil society in Nigeria. Civil society organizations rely on funding to carry out their activities, and without adequate funding, their operations can be severely hampered. Value disorientation, diverse political interests, and an unstable political system can also pose challenges, but these are not unique to civil society and can affect many other sectors as well.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>43","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY","question":"Democracy is yet to take firm root in Africa because","images":[],"options":{"A":"It retards African development","B":"African leaders are not experienced enough","C":"Most African leaders detest the will of the people.","D":"It is an expensive system of government"},"answer":"C","explanation":"Democracy is yet to take firm root in Africa mainly because most African leaders detest the will of the people. This is evident in the numerous cases of electoral malpractices, corruption, and disregard for the rule of law. Democracy is a system of government where the citizens exercise power directly or elect representatives from among themselves to form a governing body. If the leaders disregard the will of the people, then it's not a true democracy.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>44","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"Nationalism ensures the following except","images":[],"options":{"A":"national consciousness","B":"secession in a country","C":"national integration","D":"courageously necessary"},"answer":"B","explanation":"Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. It is a collective state of mind or consciousness in which people believe their nation is superior to all others. It does not encourage secession in a country, rather it promotes national unity and integration. Therefore, the statement that nationalism ensures secession in a country is incorrect.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>45","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Justice demands that people should always do what is","images":[],"options":{"A":"persistently convenient.","B":"consistently right.","C":"individually acceptable.","D":"courageously necessary."},"answer":"B","explanation":"Justice is a concept of moral rightness based on ethics, rationality, law, natural law, religion, or equity. It demands that people should always do what is consistently right. Doing what is consistently right means acting in accordance with moral or legal principles all the time. This is the essence of justice, to ensure fairness and equity in all situations.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2015>46","subject":"Civic Education","year":"2015","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Orderliness in the society is good mainly because it","images":[],"options":{"A":"discourages poverty","B":"promotes peace and stability","C":"guarantees employment for youths","D":"ensures maximum rewards from leaders"},"answer":"B","explanation":"Orderliness in the society is good mainly because it promotes peace and stability. When there is orderliness, there is a system or pattern that guides the actions and behaviors of individuals in the society. This reduces chaos, conflicts and misunderstandings, thereby promoting peace and stability. While orderliness may indirectly contribute to discouraging poverty, guaranteeing employment for youths, and ensuring maximum rewards from leaders, its primary benefit is the promotion of peace and stability in the society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>47","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Which of the following is necessary for the effective application of the rule of law?","images":[],"options":{"A":"Political will to ensure that laws are obeyed","B":"Employment opportunities for all citizens","C":"The fusion of the three arms of government","D":"Extension of the retirement age of judges"},"answer":"A","explanation":"The rule of law refers to the principle that everyone is subject to the law and equal before the law. It requires that laws are obeyed by all, including government officials, and that laws are enforced fairly and efficiently. Therefore, political will to ensure that laws are obeyed is necessary for the effective application of the rule of law. The other options do not directly relate to the rule of law.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>48","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.    Ade's action as shown in the dialogue is a demonstration of political","images":[],"options":{"A":"wisdom.","B":"apathy.","C":"lawlessness.","D":"participation."},"answer":"B","explanation":"In the dialogue, Ade expresses a lack of interest in participating in the election, indicating a sense of disillusionment with the political process. This is a demonstration of political apathy, which refers to indifference or a lack of interest in political activities such as voting or engaging in political debate. The other options do not accurately describe Ade's attitude.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>49","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY","question":"Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.  It could be inferred from the dialogue that failure to vote in an election would","images":[],"options":{"A":"guarantee citizens' right.","B":"encourage the emergence of a responsive government.","C":"promote accountability in governance.","D":"perpetuate irresponsible leadership."},"answer":"D","explanation":"From the dialogue, it can be inferred that failure to vote in an election would perpetuate irresponsible leadership. This is because, as Zubair points out, voting is a way to choose the right person for the position and change the political, economic, and social directions of the state. If citizens like Ade choose not to vote, they are indirectly allowing the continuation of irresponsible leadership.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2015>50","subject":"Civic Education","year":"2015","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : HOW LEADERS CAN PROTECT THE INTERESTS OF THEIR FOLLOWERS","question":"Use the dialogue below to answer this question   Zubair: Today is the day for gubernatorial elections. Ade, what are you waiting for? Let us go and cast our votes for candidates of our choice.    Ade: I have no interest in an election which would not yield any dividend of democracy. Our political elite are only concerned about their interest when they get to the position of authority. For crying out loud, I have made up my mind that I will not vote again.    Zubair: Haba! Ade, don't you remember Abraham Lincoln's words that 'all men are not just, all men are not true. But . . . for every scoundrel there is a hero, that for every selfish politician, there is a dedicated leader!' Come on, go and cast your vote so that we can choose the right person for the position and change the political, economic and social directions of our great state.  From the above dialogue, political leaders can encourage citizens to perform their civic duties by","images":[],"options":{"A":"fulfilling their electoral promises","B":"travelling overseas to seek for foreign investors.","C":"engaging in religious activities.","D":"visiting all the local governments in the country."},"answer":"A","explanation":"From the dialogue, it can be inferred that political leaders can encourage citizens to perform their civic duties by fulfilling their electoral promises. Ade's reluctance to vote stems from his belief that the political elite are only concerned about their own interests when they get to the position of authority. If political leaders were to fulfill their electoral promises, it would show citizens like Ade that they are indeed concerned about the welfare of the people, thereby encouraging them to participate in the electoral process.","marks":"1","difficulty":"2"}];